Code:
public int[] fix45(int[] nums) {
    int i = 0;
    while (i < nums.length && (nums[i] != 4 || (i > 0 && nums[i - 1] == 5))) {
        i++;
    }

    for (int j = 0; j < nums.length; j++) {
        if (nums[j] == 5 && (j == 0 || nums[j - 1] != 4)) {
            int temp = nums[j];
            int k = j - 1;
            while (k >= 0 && (nums[k] != 4 || nums[k + 1] == 5)) {
                k--;
            }
            nums[j] = nums[k + 1];
            nums[k + 1] = temp;
        }
    }
    return nums;
}
